// Определяем тип файла, валидируем размер.
// Маршруты:
//   ocr     — image/* | pdf | doc | docx | rtf | odt   (через OCR-сервис)
//   text    — text/plain, .txt, .md, .log              (читаем как есть)
//   table   — .xlsx, .xls, .csv                         (Spreadsheet File node)
const item = $input.first();
const binary = item.binary;

if (!binary || Object.keys(binary).length === 0) {
  return [{ json: { valid: false, error: 'Файл не загружен. Прикрепите файл.', route: 'error' } }];
}

const key = Object.keys(binary)[0];
const info = binary[key];
const fileName = info.fileName || 'unknown';
const mimeType = (info.mimeType || '').toLowerCase();
const fileSize = info.fileSize || 0;

if (fileSize > 50 * 1024 * 1024) {
  return [{ json: { valid: false, error: 'Файл слишком большой (макс. 50 МБ).', route: 'error' } }];
}

const ext = (fileName.split('.').pop() || '').toLowerCase();

let route = 'ocr';
if (mimeType.startsWith('text/plain') || ['txt','md','log'].includes(ext)) {
  route = 'text';
} else if (mimeType.includes('spreadsheet') || mimeType.includes('excel') || ['xlsx','xls','csv'].includes(ext)) {
  route = 'table';
} else if (mimeType.startsWith('image/') || mimeType.includes('pdf') || mimeType.includes('msword') || mimeType.includes('wordprocessing') || mimeType.includes('officedocument.wordprocessing') || ['pdf','doc','docx','rtf','odt','jpg','jpeg','png','tiff','tif','bmp','webp','gif','heic'].includes(ext)) {
  route = 'ocr';
} else {
  // По умолчанию пытаемся OCR — он покрывает большинство типовых документов.
  route = 'ocr';
}

return [{
  json: {
    valid: true,
    binaryKey: key,
    fileName: fileName,
    mimeType: mimeType,
    fileSize: fileSize,
    extension: ext,
    route: route
  },
  binary: binary
}];

// Извлекаем текст из ответа OCR (тот же парсер форматов что в document-loader).
try {
  const data = $input.first().json;
  if (data.error) {
    const msg = typeof data.error === 'string' ? data.error : (data.error.message || JSON.stringify(data.error));
    return [{ json: { ok: false, error: 'OCR ошибка: ' + msg } }];
  }
  let text = '';
  if (typeof data === 'string') text = data;
  else if (data.text && typeof data.text === 'string') text = data.text;
  else if (data.result && typeof data.result === 'string') text = data.result;
  else if (data.result && data.result.text) text = data.result.text;
  else if (data.content && typeof data.content === 'string') text = data.content;
  else if (data.data && typeof data.data === 'string') text = data.data;
  else if (data.output && typeof data.output === 'string') text = data.output;
  else text = JSON.stringify(data);

  if (!text || text.trim().length < 1) {
    return [{ json: { ok: false, error: 'OCR не смог распознать текст. Попробуйте другой файл.' } }];
  }

  const meta = $('Валидация и тип').first().json;
  return [{ json: {
    ok: true,
    text: text,
    fileName: meta.fileName,
    mimeType: meta.mimeType,
    source: 'ocr'
  } }];
} catch (e) {
  return [{ json: { ok: false, error: 'Ошибка обработки OCR: ' + e.message } }];
}

// Декодируем текстовый файл (txt/md/log) в строку.
// Получаем буфер через n8n helper — он сам разбирается, лежат данные в памяти
// или на диске. Прямое чтение binary.data как base64 НЕ работает в filesystem-режиме.
try {
  const meta = $('Валидация и тип').first().json;
  const buf = await this.helpers.getBinaryDataBuffer(0, meta.binaryKey);

  if (!buf || buf.length === 0) {
    return [{ json: { ok: false, error: 'Файл пустой или не удалось прочитать содержимое.' } }];
  }

  function decodeUtf8(b) {
    if (b[0] === 0xEF && b[1] === 0xBB && b[2] === 0xBF) return b.slice(3).toString('utf8');
    return b.toString('utf8');
  }
  function decodeUtf16le(b) {
    if (b[0] === 0xFF && b[1] === 0xFE) return b.slice(2).toString('utf16le');
    return b.toString('utf16le');
  }
  function countReplacement(s) {
    let n = 0;
    for (let i = 0; i < s.length; i++) if (s.charCodeAt(i) === 0xFFFD) n++;
    return n;
  }
  // CP1251 → Unicode: ручная таблица, в Node нет встроенного.
  const CP1251_TO_UNICODE = (function () {
    const map = new Array(256);
    for (let i = 0; i < 128; i++) map[i] = i;
    const high = 'ЂЃ‚ѓ„…†‡€‰Љ‹ЊЌЋЏ'
      + 'ђ‘’“”•–—?™љ›њќћџ'
      + ' ЎўЈ¤Ґ¦§Ё©Є«¬­®Ї'
      + '°±Ііґµ¶·ё№є»јЅѕї';
    for (let i = 0; i < high.length; i++) map[128 + i] = high.charCodeAt(i);
    for (let i = 0; i < 64; i++) map[0xC0 + i] = 0x0410 + i;
    return map;
  })();
  function decodeCp1251(b) {
    let s = '';
    for (let i = 0; i < b.length; i++) s += String.fromCharCode(CP1251_TO_UNICODE[b[i]]);
    return s;
  }

  let text;
  if (buf.length >= 2 && buf[0] === 0xFF && buf[1] === 0xFE) {
    text = decodeUtf16le(buf);
  } else {
    const asUtf8 = decodeUtf8(buf);
    const bad = countReplacement(asUtf8);
    if (bad === 0) {
      text = asUtf8;
    } else {
      const asCp = decodeCp1251(buf);
      text = (countReplacement(asCp) < bad) ? asCp : asUtf8;
    }
  }

  if (!text || text.length < 1) {
    return [{ json: { ok: false, error: 'Файл пустой.' } }];
  }

  return [{ json: {
    ok: true,
    text: text,
    fileName: meta.fileName,
    mimeType: meta.mimeType,
    source: 'text'
  } }];
} catch (e) {
  return [{ json: { ok: false, error: 'Ошибка чтения текстового файла: ' + e.message } }];
}

// Форматирует результат Spreadsheet File node в выровненный текст.
// Распознаёт два формата строк:
//   1) rawData=true: { row: [cell1, cell2, ...] } — массив ячеек
//   2) headers:      { ColA: v1, ColB: v2, ... }  — объект с именованными колонками
// Подстраивается под неравномерные строки (разное число колонок).
try {
  const meta = $('Валидация и тип').first().json;
  const rows = $input.all().map(r => r.json);

  if (rows.length === 0) {
    return [{ json: { ok: false, error: 'В таблице нет данных.' } }];
  }

  // Форматирование одной ячейки в строку.
  function fmtCell(v) {
    if (v === null || v === undefined) return '';
    if (typeof v === 'object') return JSON.stringify(v);
    // Числа выводим как есть — без округления и потери точности.
    // То что лежит в файле — то и показываем.
    if (typeof v === 'number') return String(v);
    return String(v);
  }

  // Детектируем формат и собираем массив массивов ячеек.
  let header = null;
  let cellRows;
  const firstRow = rows[0];
  const firstKeys = Object.keys(firstRow);
  if (firstKeys.length === 1 && firstKeys[0] === 'row' && Array.isArray(firstRow.row)) {
    // rawData mode
    cellRows = rows.map(r => Array.isArray(r.row) ? r.row.map(fmtCell) : []);
  } else {
    // Header mode — собираем имена колонок в порядке появления
    const colOrder = [];
    const seen = new Set();
    for (const r of rows) {
      for (const k of Object.keys(r)) {
        if (!seen.has(k)) { seen.add(k); colOrder.push(k); }
      }
    }
    header = colOrder;
    cellRows = rows.map(r => colOrder.map(c => fmtCell(r[c])));
  }

  // Определяем максимальное число колонок (учитываем неровные строки).
  let maxCols = header ? header.length : 0;
  for (const row of cellRows) {
    if (row.length > maxCols) maxCols = row.length;
  }
  if (maxCols === 0) {
    return [{ json: { ok: false, error: 'Все строки таблицы пусты.' } }];
  }

  // Считаем ширины колонок.
  const widths = new Array(maxCols).fill(0);
  if (header) {
    for (let i = 0; i < header.length; i++) {
      widths[i] = Math.max(widths[i], String(header[i]).length);
    }
  }
  for (const row of cellRows) {
    for (let i = 0; i < row.length; i++) {
      widths[i] = Math.max(widths[i], row[i].length);
    }
  }
  // Ограничиваем максимум ~60 символов на колонку.
  for (let i = 0; i < widths.length; i++) {
    widths[i] = Math.min(widths[i], 60);
  }

  function pad(s, w) {
    s = (s.length > w) ? s.slice(0, w - 1) + '…' : s;
    return s + ' '.repeat(Math.max(0, w - s.length));
  }

  const lines = [];
  if (header) {
    lines.push(header.map((c, i) => pad(String(c), widths[i])).join('  '));
    lines.push(widths.map(w => '-'.repeat(w)).join('  '));
  }
  for (const row of cellRows) {
    // Если в строке меньше колонок — добивать пустыми;
    // но финальный trimEnd убирает хвостовые пробелы для коротких строк.
    const padded = [];
    for (let i = 0; i < maxCols; i++) {
      padded.push(pad(row[i] !== undefined ? row[i] : '', widths[i]));
    }
    lines.push(padded.join('  ').replace(/\s+$/, ''));
  }

  return [{ json: {
    ok: true,
    text: lines.join('\n'),
    fileName: meta.fileName,
    mimeType: meta.mimeType,
    source: 'table',
    rowCount: cellRows.length,
    colCount: maxCols
  } }];
} catch (e) {
  return [{ json: { ok: false, error: 'Ошибка обработки таблицы: ' + e.message } }];
}

// Унифицированный финальный ответ для всех веток.
const data = $input.first().json;
if (!data.ok) {
  return [{ json: { response: data.error || 'Не удалось извлечь текст.', success: false } }];
}
return [{ json: {
  response: data.text,
  success: true,
  fileName: data.fileName,
  mimeType: data.mimeType,
  source: data.source,
  rowCount: data.rowCount,
  colCount: data.colCount,
  length: (data.text || '').length
} }];
